const error = $input.first().json;

const workflowName  = error.workflow?.name     || 'unknown_workflow';
const executionId   = error.execution?.id      || 'unknown_execution';
const errorMessage  = error.execution?.error?.message || error.error?.message || 'Error desconocido';
const errorNode     = error.execution?.lastNodeExecuted || 'unknown_node';
const timestamp     = new Date().toISOString();

let projectId = null;
try {
  const execData = error.execution?.data?.resultData?.runData;
  if (execData) {
    for (const nodeName of Object.keys(execData)) {
      const nodeRuns = execData[nodeName];
      if (nodeRuns && nodeRuns[0] && nodeRuns[0].data && nodeRuns[0].data.main) {
        const items = nodeRuns[0].data.main[0];
        if (items && items[0] && items[0].json && items[0].json.project_id) {
          const pid = items[0].json.project_id;
          if (/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(pid)) {
            projectId = pid;
            break;
          }
        }
      }
    }
  }
} catch(e) {}

const criticalWorkflows = ['main_orchestrator', 'agent_proposal', 'agent_trades', 'init_new_project'];
const isCritical = criticalWorkflows.includes(workflowName);

// Excluir workflows temporales/test/debug del envio de emails (siguen logueando)
const silentPattern = /(_TEMP$|^debug|^test_|TEMP|migration_)/i;
const isSilentWorkflow = silentPattern.test(workflowName);

return [{
  json: {
    workflow_name:    workflowName,
    execution_id:     executionId,
    error_message:    errorMessage,
    error_node:       errorNode,
    project_id:       projectId,
    is_critical:      isCritical,
    is_silent:        isSilentWorkflow,
    timestamp:        timestamp,
    error_summary:    `[${workflowName}] Nodo: ${errorNode} — ${errorMessage.substring(0, 300)}`
  }
}];
